document.addEventListener("alpine:init",()=>{Alpine.data("portfolioModal",()=>({open:!1,items:[],index:0,title:"",get current(){return this.items[this.index]??null},get hasMany(){return this.items.length>1},openAt(e,t,i){this.items=t,this.index=e,this.title=i,this.open=!0,this.$nextTick(()=>{document.getElementById("portfolio-modal")?.showModal()})},close(){this.open=!1,document.getElementById("portfolio-modal")?.close();const e=document.querySelector("#portfolio-modal video");e&&e.pause()},goTo(e){const t=document.querySelector("#portfolio-modal video");t&&t.pause(),this.index=e},prev(){this.goTo((this.index-1+this.items.length)%this.items.length)},next(){this.goTo((this.index+1)%this.items.length)},handleKeydown(e){this.open&&("ArrowLeft"===e.key&&this.prev(),"ArrowRight"===e.key&&this.next(),"Escape"===e.key&&this.close())}}))});